import { useState, useRef, useCallback, useEffect, memo } from "react";
import { Music, Music2 } from "lucide-react";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";

// Fallback tracks in case DB is empty
const FALLBACK_TRACKS = [
  "/music/blues1.mp3",
  "/music/blues2.mp3",
  "/music/blues3.mp3",
  "/music/blues4.mp3",
  "/music/blues5.mp3",
  "/music/blues6.mp3",
];

interface HeroMusicButtonProps {
  className?: string;
}

const HeroMusicButton = memo(({ className = "" }: HeroMusicButtonProps) => {
  const [isPlaying, setIsPlaying] = useState(false);
  const audioRef = useRef<HTMLAudioElement | null>(null);
  const trackIndexRef = useRef(0);
  const isPlayingRef = useRef(false);

  const { data: dbTracks } = useQuery({
    queryKey: ["background-music"],
    queryFn: async () => {
      const { data } = await supabase
        .from("background_music")
        .select("file_url")
        .eq("is_active", true)
        .order("sort_order");
      return data?.map((t) => t.file_url) || [];
    },
    staleTime: 10 * 60 * 1000,
  });

  const tracks = dbTracks && dbTracks.length > 0 ? dbTracks : FALLBACK_TRACKS;

  // Shuffle tracks on first use
  const shuffledTracksRef = useRef<string[]>([]);
  useEffect(() => {
    const shuffled = [...tracks].sort(() => Math.random() - 0.5);
    shuffledTracksRef.current = shuffled;
    trackIndexRef.current = 0;
  }, [tracks]);

  useEffect(() => {
    return () => {
      isPlayingRef.current = false;
      const audio = audioRef.current;
      if (audio) {
        audio.onended = null;
        audio.onerror = null;
        audio.pause();
        audio.removeAttribute("src");
        audio.load();
        audioRef.current = null;
      }
    };
  }, []);

  const consecutiveErrorsRef = useRef(0);
  const MAX_CONSECUTIVE_ERRORS = 3;

  const stopAudio = useCallback(() => {
    isPlayingRef.current = false;
    setIsPlaying(false);

    const audio = audioRef.current;
    if (audio) {
      audio.onended = null;
      audio.onerror = null;
      audio.pause();
      audio.removeAttribute("src");
      audio.load();
      audioRef.current = null;
    }
  }, []);

  const playTrack = useCallback((index: number) => {
    const list = shuffledTracksRef.current;
    if (list.length === 0) return;

    if (!isPlayingRef.current) return;

    if (consecutiveErrorsRef.current >= MAX_CONSECUTIVE_ERRORS) {
      console.warn("Audio: too many consecutive errors, stopping playback");
      stopAudio();
      consecutiveErrorsRef.current = 0;
      return;
    }

    const idx = index % list.length;
    trackIndexRef.current = idx;

    // Reuse existing audio element to preserve user gesture unlock
    const audio = audioRef.current;
    if (!audio) {
      console.warn("Audio: element missing, stopping playback");
      stopAudio();
      return;
    }

    audio.src = list[idx];

    audio.onended = () => {
      consecutiveErrorsRef.current = 0;
      if (isPlayingRef.current) {
        playTrack(idx + 1);
      }
    };

    audio.onerror = () => {
      consecutiveErrorsRef.current += 1;
      if (isPlayingRef.current) {
        playTrack(idx + 1);
      }
    };

    audio.play().catch(() => {
      // If play fails on subsequent track, try once more with load()
      if (!isPlayingRef.current) return;
      audio.load();
      audio.play().catch(() => {
        stopAudio();
      });
    });
  }, [stopAudio]);

  const toggleMusic = useCallback(() => {
    if (isPlayingRef.current) {
      stopAudio();
    } else {
      isPlayingRef.current = true;
      setIsPlaying(true);
      consecutiveErrorsRef.current = 0;

      // Create & unlock audio element synchronously within user gesture
      const audio = new Audio();
      audio.volume = 0.3;
      audio.crossOrigin = "anonymous";
      audioRef.current = audio;
      // Unlock on mobile by calling play() immediately (plays silence)
      audio.play().catch(() => {});

      // Randomize start track each time music is turned on
      const listLength = shuffledTracksRef.current.length;
      if (listLength > 0) {
        const previousIndex = trackIndexRef.current;
        let randomIndex = Math.floor(Math.random() * listLength);
        if (listLength > 1 && randomIndex === previousIndex) {
          randomIndex = (randomIndex + 1) % listLength;
        }
        trackIndexRef.current = randomIndex;
      }

      playTrack(trackIndexRef.current);
    }
  }, [playTrack, stopAudio]);

  return (
    <button
      onClick={toggleMusic}
      className={`group w-9 h-9 rounded-full flex items-center justify-center transition-all duration-300 shadow-lg cursor-pointer bg-primary text-primary-foreground hover:bg-primary/90 ${
        isPlaying ? "ring-2 ring-primary/50 animate-pulse" : ""
      } ${className}`}
      aria-label={isPlaying ? "Mute background music" : "Play background music"}
    >
      {isPlaying ? (
        <Music className="w-4 h-4 drop-shadow-sm" />
      ) : (
        <Music2 className="w-4 h-4 group-hover:scale-110 transition-transform" />
      )}
    </button>
  );
});

HeroMusicButton.displayName = "HeroMusicButton";

export default HeroMusicButton;
